/**
 * funzione eseguita ogni volta che il valore del knob cambia
 */
void knobValueRead(lv_event_t *e)
{
	arcLastTouchTime = millis();

	// flag cambiamento
	SETPOINT_CHANGED = true;
	lv_label_set_text(ui_debugLabel, "chg");
	// Define the global label object generated by SquareLine Studio
	extern lv_obj_t *ui_setPointNum;

	lv_obj_t *obj = lv_event_get_target(e);
	int32_t current_value = lv_arc_get_value(obj);

	// --- 1. Rounding to Nearest 0.5 (or nearest multiple of 5 in raw integer) ---

	int32_t remainder = current_value % 5;

	// Adjust the raw value to the nearest multiple of 5 (rounding logic)
	if (remainder != 0)
	{
		if (abs(remainder) >= 3)
		{
			// Round up/down toward the nearest multiple of 5
			current_value += (current_value > 0) ? (5 - remainder) : (-5 - remainder);
		}
		else
		{
			// Round down/up toward zero
			current_value -= remainder;
		}
	}

	// --- 2. Formatting to X.Y Decimal String with Unit ---

	int32_t wholePart = current_value / 10;
	int8_t decimalDigit = abs(current_value % 10);

	// Define buffer. Needs to be larger to hold the unit (e.g., "-100.0 °C\0" needs ~10 chars)
	char buffer[16];

	// Format: Long integer (. ), Integer, followed by the literal string " °C"
	snprintf(buffer, sizeof(buffer), "%ld.%d °C", wholePart, decimalDigit);

	// 3. Update the LVGL Label
	if (ui_setPointNum != NULL)
	{
		lv_label_set_text(ui_setPointNum, buffer);
	}
}
void knobReleased(lv_event_t *e)
{
	azzera_counter = millis();
	uint16_t valuez = lv_arc_get_value(ui_Arc1);
	float valuezz = ((valuez / 10.0f) * 10.0f) / 10.0f;
	display_confirm_setpoint(tButton, valuezz);
	lv_label_set_text_fmt(ui_debugLabel, "%d", tButton);
}

