void pulsanteControlloRemoto(lv_event_t *e)
{
	switchLastTouchTime = lv_tick_get();
	bool is_on = lv_obj_has_state(ui_Switch1, LV_STATE_CHECKED);
	float newVal = is_on ? (float)display_get_max(tButton) : (float)display_get_min(tButton);
	newSetPoint[tButton] = newVal;
	display_set_setpoint(tButton, newVal);
	valueChanged[tButton] = 1;
	lv_label_set_text(ui_labelONOFF, is_on ? "ON" : "OFF");
}
